mapper.select:
SELECT s.staff_id, s.staff_no, s.provider_id, s.staff_name, s.gender, s.birth_date, s.age,
       s.id_card, s.phone, s.email, s.address, s.emergency_contact, s.emergency_phone,
       s.education, s.photo_url AS avatar_url, s.status, s.work_status, s.audit_remark,
       s.hire_date, s.leave_date, s.leave_reason, s.nation, s.political_status,
       s.marital_status, s.domicile_address, s.residence_address, s.service_types,
       s.remark, s.create_time, s.update_time, s.deleted, s.insurance_status, s.monthly_star, s.quarterly_star,
       p.provider_name
FROM t_staff s
LEFT JOIN t_provider p ON s.provider_id = p.provider_id
WHERE s.deleted = 0

    AND s.staff_name LIKE CONCAT('%', #{query.staffName}, '%')


    AND s.staff_no = #{query.staffNo}


    AND s.phone = #{query.phone}


    AND s.id_card = #{query.idCard}


    AND s.status = #{query.status}


    AND s.provider_id = #{query.providerId}


    AND s.service_types LIKE CONCAT('%', #{query.serviceType}, '%')


    AND s.hire_date >= #{query.hireDateStart}


    AND s.hire_date <= #{query.hireDateEnd}


    AND s.insurance_status = #{query.insuranceStatus}

ORDER BY s.create_time DESC

mapper.update:
UPDATE t_staff
staff_name = #{staffName}, gender = #{gender}, id_card = #{idCard}, age = #{age}, phone = #{phone}, birth_date = #{birthDate}, nation = #{nation}, education = #{education}, political_status = #{politicalStatus}, marital_status = #{maritalStatus}, domicile_address = #{domicileAddress}, residence_address = #{residenceAddress}, emergency_contact = #{emergencyContact}, emergency_phone = #{emergencyPhone}, service_types = #{serviceTypes}, hire_date = #{hireDate}, leave_date = #{leaveDate}, leave_reason = #{leaveReason}, photo_url = #{avatarUrl}, remark = #{remark}, status = #{status}, insurance_status = #{insuranceStatus}, monthly_star = #{monthlyStar}, quarterly_star = #{quarterlyStar}, update_time = NOW()
WHERE staff_id = #{staffId}
